class Solution:
    def resultingString(self, s: str) -> str:
        stack = []
        for char in s:
            if stack and (ord(char) - ord(stack[-1]) == 1 or ord(char) - ord(stack[-1]) == -1 or (ord(char) == ord('a') and ord(stack[-1]) == ord('z')) or (ord(char) == ord('z') and ord(stack[-1]) == ord('a'))):
                stack.pop()
            else:
                stack.append(char)
        return ''.join(stack)
